function toSegments(path) {
  if (Array.isArray(path)) return path;
  if (typeof path !== 'string') return null;
  const s = path.trim();
  if (!s) return [];
  return s.split('.');
}

function isIndex(seg) {
  if (typeof seg === 'number') return Number.isInteger(seg) && seg >= 0;
  if (typeof seg !== 'string') return false;
  return /^(0|[1-9]\d*)$/.test(seg);
}

function cloneShallow(x) {
  if (Array.isArray(x)) return x.slice();
  if (x && typeof x === 'object') return { ...x };
  return null;
}

export default function setByPath(obj, path, value) {
  const segs = toSegments(path);
  if (!segs) throw new TypeError('setByPath: path must be a string or array');
  if (segs.length === 0) return value;

  function setRec(current, idx) {
    const seg = segs[idx];
    const last = idx === segs.length - 1;

    const shouldBeArray = isIndex(seg);

    let base;
    if (Array.isArray(current)) base = current;
    else if (current && typeof current === 'object') base = current;
    else base = shouldBeArray ? [] : {};

    const copy = cloneShallow(base);
    const key = isIndex(seg) ? +seg : seg;

    if (last) {
      copy[key] = value;
      return copy;
    }

    const child = base[key];
    copy[key] = setRec(child, idx + 1);
    return copy;
  }

  return setRec(obj, 0);
}
